// ============================================
// HTML ESCAPE HELPER (XSS Protection)
// ============================================
const esc = (s = '') => String(s)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;')
  .replaceAll("'", '&#39;');

// ============================================
// GET THE ORDER DATA
// ============================================
const order = $input.first().json.body || $input.first().json;
const items = order.items || [];

// ============================================
// TAX SETTINGS
// Pass taxRate in payload (0.13 = 13%) or defaults to 0
// ============================================
const TAX_RATE = order.taxRate ?? 0;

// ============================================
// DOCUMENT TYPE SETTINGS
// Options: invoice, quote, receipt, estimate, proforma
// ============================================
const docType = (order.documentType || 'invoice').toLowerCase();

const typeSettings = {
  invoice: {
    title: 'INVOICE',
    numberLabel: 'Invoice #',
    numberPrefix: 'INV-',
    customerLabel: 'Bill To',
    showDueDate: true,
    showPaymentMethod: false,
    showValidUntil: false
  },
  quote: {
    title: 'QUOTE',
    numberLabel: 'Quote #',
    numberPrefix: 'QTE-',
    customerLabel: 'Quote For',
    showDueDate: false,
    showPaymentMethod: false,
    showValidUntil: true
  },
  estimate: {
    title: 'ESTIMATE',
    numberLabel: 'Estimate #',
    numberPrefix: 'EST-',
    customerLabel: 'Prepared For',
    showDueDate: false,
    showPaymentMethod: false,
    showValidUntil: true
  },
  receipt: {
    title: 'RECEIPT',
    numberLabel: 'Receipt #',
    numberPrefix: 'REC-',
    customerLabel: 'Received From',
    showDueDate: false,
    showPaymentMethod: true,
    showValidUntil: false
  },
  proforma: {
    title: 'PROFORMA INVOICE',
    numberLabel: 'Proforma #',
    numberPrefix: 'PRO-',
    customerLabel: 'Bill To',
    showDueDate: true,
    showPaymentMethod: false,
    showValidUntil: false
  }
};

// Use invoice as fallback if unknown type
const settings = typeSettings[docType] || typeSettings.invoice;

// ============================================
// BUILD THE ITEMS TABLE ROWS
// ============================================
let itemsHtml = '';
let subtotal = 0;

for (const item of items) {
  const lineTotal = item.quantity * item.price;
  subtotal += lineTotal;

  itemsHtml += '<tr>';
  itemsHtml += '<td>' + esc(item.name) + '</td>';
  itemsHtml += '<td>' + esc(item.quantity) + '</td>';
  itemsHtml += '<td>$' + item.price.toFixed(2) + '</td>';
  itemsHtml += '<td>$' + lineTotal.toFixed(2) + '</td>';
  itemsHtml += '</tr>';
}

// ============================================
// CALCULATE TOTALS
// ============================================
const tax = subtotal * TAX_RATE;
const total = subtotal + tax;

// ============================================
// SET DEFAULT VALUES (all escaped)
// ============================================
const company = esc(order.company || 'Your Company');
const docNumber = esc(order.documentNumber || order.invoiceNumber || settings.numberPrefix + Date.now());
const docDate = new Date().toLocaleDateString();
const customerName = esc(order.customerName || 'Customer');
const customerEmail = esc(order.customerEmail || '');
const customerAddress = esc(order.customerAddress || '');
const dueDate = esc(order.dueDate || '');
const validUntil = esc(order.validUntil || '');
const paymentMethod = esc(order.paymentMethod || '');
const notes = esc(order.notes || '');
const logoUrl = order.logoUrl || '';

// ============================================
// BUILD OPTIONAL FIELDS
// ============================================
let logoHtml = '';
if (logoUrl) {
  logoHtml = '<img src="' + esc(logoUrl) + '" style="max-height: 60px; max-width: 200px;" alt="Logo">';
}

let optionalFields = '';

if (settings.showDueDate && dueDate) {
  optionalFields += '<p><strong>Due Date:</strong> ' + dueDate + '</p>';
}

if (settings.showValidUntil && validUntil) {
  optionalFields += '<p><strong>Valid Until:</strong> ' + validUntil + '</p>';
}

if (settings.showPaymentMethod && paymentMethod) {
  optionalFields += '<p><strong>Payment Method:</strong> ' + paymentMethod + '</p>';
}

let notesHtml = '';
if (notes) {
  notesHtml = '<div class="notes"><strong>Notes:</strong><br>' + notes + '</div>';
}

let addressHtml = '';
if (customerAddress) {
  addressHtml = '<p><strong>Address:</strong> ' + customerAddress + '</p>';
}

// Tax row only if tax rate > 0
let taxHtml = '';
if (TAX_RATE > 0) {
  taxHtml = '<p class="right">Tax (' + (TAX_RATE * 100) + '%): $' + tax.toFixed(2) + '</p>';
}

// ============================================
// BUILD THE HTML
// ============================================
const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial; padding: 40px; }
    .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 20px; }
    .company-info h1 { color: #333; margin: 0 0 5px 0; }
    .company-info h2 { color: #666; margin: 0; }
    table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    th, td { padding: 10px; text-align: left; border-bottom: 1px solid #ccc; }
    th { background: #f0f0f0; }
    .right { text-align: right; }
    .bold { font-weight: bold; font-size: 18px; }
    .notes { margin-top: 30px; padding: 15px; background: #f9f9f9; border-left: 3px solid #ccc; }
  </style>
</head>
<body>

  <div class="header">
    <div class="company-info">
      <h1>${company}</h1>
      <h2>${settings.title}</h2>
    </div>
    ${logoHtml}
  </div>

  <p><strong>${settings.numberLabel}:</strong> ${docNumber}</p>
  <p><strong>Date:</strong> ${docDate}</p>
  ${optionalFields}
  <p><strong>${settings.customerLabel}:</strong> ${customerName}</p>
  ${addressHtml}
  <p><strong>Email:</strong> ${customerEmail}</p>

  <table>
    <tr>
      <th>Item</th>
      <th>Qty</th>
      <th>Price</th>
      <th>Total</th>
    </tr>
    ${itemsHtml}
  </table>

  <p class="right">Subtotal: $${subtotal.toFixed(2)}</p>
  ${taxHtml}
  <p class="right bold">Total: $${total.toFixed(2)}</p>

  ${notesHtml}

</body>
</html>
`;

// ============================================
// RETURN THE RESULT
// ============================================
return [{ 
  json: { 
    html: html, 
    documentNumber: order.documentNumber || order.invoiceNumber || settings.numberPrefix + Date.now(),
    documentType: docType,
    customerEmail: order.customerEmail || '' 
  } 
}];
